instruction:
A function template works with any type. `T` is a placeholder replaced at compile time:

```cpp
template <typename T>
T max(T a, T b) {
    return (a > b) ? a : b;
}
```

The compiler generates a separate `max<int>`, `max<double>`, etc.

starter:
#include <iostream>
#include <string>
using namespace std;

template <typename T>
T myMax(T a, T b) {
    return (a > b) ? a : b;
}

template <typename T>
void swap(T& a, T& b) {
    T temp = a;
    a = b;
    b = temp;
}

template <typename T>
void printArray(const T arr[], int size) {
    for (int i = 0; i < size; i++)
        cout << arr[i] << " ";
    cout << endl;
}

int main() {
    cout << myMax(10, 20)      << endl;  // int
    cout << myMax(3.14, 2.71)  << endl;  // double
    cout << myMax(string("z"), string("a")) << endl;  // string!

    int a = 5, b = 10;
    swap(a, b);
    cout << a << " " << b << endl;

    double arr[] = {3.0, 1.0, 4.0, 1.0, 5.0};
    printArray(arr, 5);

    return 0;
}

instruction:
Template classes work with any type:

```cpp
template <typename T>
class Box {
    T value;
public:
    Box(T v) : value(v) {}
    T get() { return value; }
};

Box<int>    intBox(42);
Box<string> strBox("hello");
```

