#include <iostream>
#include <string>
using namespace std;

template <typename T>
class Stack {
    vector<T> data;

public:
    void push(const T& val) { data.push_back(val); }

    T pop() {
        T top = data.back();
        data.pop_back();
        return top;
    }

    T peek() const { return data.back(); }
    bool empty() const { return data.empty(); }
    size_t size() const { return data.size(); }
};

#include <vector>

int main() {
    Stack<int> intStack;
    intStack.push(10);
    intStack.push(20);
    intStack.push(30);
    cout << intStack.pop() << endl;  // 30
    cout << intStack.peek() << endl; // 20

    Stack<string> strStack;
    strStack.push("C++");
    strStack.push("is");
    strStack.push("awesome");
    while (!strStack.empty())
        cout << strStack.pop() << " ";
    cout << endl;

    return 0;
}

instruction:
Templates can have multiple type parameters:

```cpp
template <typename K, typename V>
class Pair {
    K first;
    V second;
};
```

This is how `std::pair<K,V>` and `std::map<K,V>` work.

starter:
#include <iostream>
#include <string>
using namespace std;

template <typename T1, typename T2>
struct Pair {
    T1 first;
    T2 second;

    Pair(T1 a, T2 b) : first(a), second(b) {}

    void print() const {
        cout << "(" << first << ", " << second << ")" << endl;
    }
};

template <typename K, typename V>
Pair<K,V> makePair(K k, V v) {
    return Pair<K,V>(k, v);
}

int main() {
    Pair<string, int> nameAge("Alice", 30);
    Pair<int, double> idScore(1001, 95.5);

    nameAge.print();
    idScore.print();

    auto p = makePair("Bob", 3.14);
    p.print();

    return 0;
}

instruction:
Provide a specific implementation for a particular type:

```cpp
template <>         // full specialization for char*
bool isNull<char*>(char* p) {
    return p == nullptr || *p == '\0';
}
```

Useful when the general template doesn't work correctly for a specific type.

starter:
#include <iostream>
#include <string>
using namespace std;

template <typename T>
string describe(T val) {
    return "Value: " + to_string(val);
}

// Specialization for bool:
template <>
string describe<bool>(bool val) {
    return string("Bool: ") + (val ? "true" : "false");
}

// Specialization for string:
template <>
string describe<string>(string val) {
    return "String: '" + val + "' (len=" + to_string(val.length()) + ")";
}

int main() {
    cout << describe(42)         << endl;
    cout << describe(3.14)       << endl;
    cout << describe(true)       << endl;  // uses specialization
    cout << describe(string("hi")) << endl;  // uses specialization

    return 0;
}
